#!/usr/bin/env python3
"""
Apply Claude's Analyst Workspace UI as a Streamlit-embedded HTML shell.

Run this from your project root:
  cd /Users/roberttabamo/Desktop/ai-deal-pipeline-assistant
  python apply_claude_ui.py
"""

from pathlib import Path
import base64
import sys

project_root = Path.cwd()
app_path = project_root / "app.py"
ui_dir = project_root / "src" / "ui"
html_path = ui_dir / "analyst_workspace.html"

if not app_path.exists():
    raise SystemExit("Error: app.py not found. Run this script from the project root.")

backup_path = project_root / "app.py.before-claude-ui-bak"
if not backup_path.exists():
    backup_path.write_text(app_path.read_text(encoding="utf-8"), encoding="utf-8")

ui_dir.mkdir(parents=True, exist_ok=True)

html_b64 = ""
html_path.write_text(base64.b64decode(html_b64).decode("utf-8"), encoding="utf-8")

app_wrapper = 'from pathlib import Path\n\nimport streamlit as st\nimport streamlit.components.v1 as components\n\n\nst.set_page_config(\n    page_title="DealFlow AI",\n    page_icon="💎",\n    layout="wide",\n    initial_sidebar_state="collapsed",\n)\n\nst.markdown(\n    """\n    <style>\n    #MainMenu,\n    footer,\n    header,\n    [data-testid="stHeader"],\n    [data-testid="stToolbar"],\n    [data-testid="stDecoration"],\n    [data-testid="stStatusWidget"] {\n        display: none !important;\n        visibility: hidden !important;\n        height: 0 !important;\n        min-height: 0 !important;\n    }\n\n    .stApp {\n        background: #0a0e1a;\n    }\n\n    .block-container {\n        padding: 0 !important;\n        margin: 0 !important;\n        max-width: 100% !important;\n    }\n\n    iframe {\n        display: block;\n        width: 100%;\n        border: 0;\n    }\n    </style>\n    """,\n    unsafe_allow_html=True,\n)\n\nhtml_path = Path("src/ui/analyst_workspace.html")\n\nif not html_path.exists():\n    st.error("Missing UI file: src/ui/analyst_workspace.html")\n    st.stop()\n\nhtml = html_path.read_text(encoding="utf-8")\ncomponents.html(html, height=1120, scrolling=True)\n'
app_path.write_text(app_wrapper, encoding="utf-8")

print("Applied Claude Analyst Workspace UI.")
print(f"Backup saved: {backup_path}")
print(f"HTML UI saved: {html_path}")
print("Next:")
print("  python -m py_compile app.py")
print("  python -m streamlit run app.py")
